var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"젠장. 이러다가 날 새겠네!","JPN":"もうっ、このままじゃ埒が明かない！","ENG":"Damn it. It's going to become dawn soon!","TWN":"可惡。這樣下去天都要亮了！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레! 제가 길을 뚫을 테니 실장님이랑 같이…!","JPN":"クレデレ！　私が突破してルートを作るから、あなたは室長と一緒に……！","ENG":"Credere! I'll make the way, so go forth with the chief–","TWN":"克蕾妲莉！我去前面，你和室長一起……！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"조심해, 유피!!","JPN":"危ない、ユピ！！","ENG":"Yuppie, watch out!","TWN":"小心，悠菲！！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Eeek!","TWN":"哎呀？！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"찾았다, 악의 사도!","JPN":"見つけたわ、悪党め！","ENG":"Here you are, you servant of evil!","TWN":"找到了，邪惡的使徒！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"여태까지 이런 섬에 잘도 숨어있었구나!","JPN":"よくもこんな島に隠れていたわね！","ENG":"To think that you were hidden away on such an island!","TWN":"竟然躲在這座島上，真有你的！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"여기서 뭔 정모라도 열렸어요? 아까부터 뭐가 이렇게 계속 튀어나와?","JPN":"みんなここに来るよう、誰かに言われたんですか？　次から次へと……！","ENG":"What is this, a family reunion? What's up with all the random appearances?","TWN":"現在是開派對嗎？怎麼從剛才開始一直有人冒出來！？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"적의 적은 달리 말하면 아군인 셈.","JPN":"敵の敵は、味方も同然。","ENG":"My enemy's enemy is my ally.","TWN":"敵人的敵人，也就是我們的朋友。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"기밀 유출범이 탈옥했다는 소식에 경찰청과는 임시동맹을 맺었지.","JPN":"機密漏洩の犯人が脱獄したと聞いて、一時的に警察庁と同盟を結んだのさ。","ENG":"We allied with the police as the criminal who leaked information broke out of prison.","TWN":"聽說洩密者越獄了，我們便和警察局暫時結成了同盟。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"그것뿐만이 아닙니다. 섬의 보물을 찾고자 제 동생 또한 이곳으로 오고 있지요.","JPN":"私たちだけじゃありません。島のお宝を目当てにこれから私の弟もやってきます。","ENG":"Not only that. My little brother is also on his way here to find the treasure.","TWN":"不僅如此，為了尋找島上的寶物，我的弟弟也正在趕來這裡。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"그래요. 당신들 같은 가짜가 아닌 프론트베이의 진짜 해적이!","JPN":"そう、あなたたちのような偽物ではなく、フロントベイの本物の海賊が！","ENG":"Yeah, I said it. He's a real pirate of Front Bay, unlike you all!","TWN":"看好了！我們才是真正的前灣海盜，不像你們這些冒牌貨！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"가짜가 아니야! 시그마 해적단은 무시무시한 바다 사나이라구!","JPN":"偽物じゃない！　シグマ海賊団は正真正銘、恐ろしい海の漢たちだもん！","ENG":"We're real pirates too! The Sigma Pirates are fearsome seafaring people!","TWN":"什麼冒牌貨！西格瑪海盜團可是非常可怕的海上女子漢！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 거 반박하지 말고 저 좀 도와주세요, 실장님! 이러다 죽겠다고요!","JPN":"くだらないことに反論していないで、こっちを手伝ってくださいよ、室長！　本当に死んでしまいます！","ENG":"Maybe just let that detail go and help me out here, Chief?! I'm about to die over here!","TWN":"別再鬥嘴了，快幫幫我，室長！這樣下去我會死的！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"파, 팔에 힘이…!","JPN":"う、腕に力が……！","ENG":"M-my arm's...!","TWN":"我的手臂，沒力氣了…！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"치잇!","JPN":"ちっ！","ENG":"Tsk!","TWN":"嘖！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"당신들의 기묘한 포즈. 아까부터 마음에 들지 않았습니다.","JPN":"あなたたちの変なポーズ。さっきからずっと目障りです。","ENG":"Your bizarre pose has been bothering me for a while.","TWN":"克蕾妲莉就看不順眼你們那些奇怪的姿勢。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레가 혼쭐을 내드리죠.","JPN":"そんなあなたたちは、クレデレが痛い目に合わせてあげましょう。","ENG":"Credere will teach you a lesson.","TWN":"克蕾妲莉會好好教訓你們的。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"선장님, 유피. 여긴 크레데레에게 맡겨주시길.","JPN":"船長、ユピ、ここはクレデレにお任せあれ。","ENG":"Captain! Yuppie! Leave this to Credere.","TWN":"船長，悠菲。這裡就交給克蕾妲莉吧。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"저 빠릿한 몸놀림. 아무래도 크레데레의 상대인 것 같습니다.","JPN":"あのすばしっこいのは、クレデレが相手します。","ENG":"That agile movement tells me they are a good match for Credere.","TWN":"那敏捷的身手，正配做克蕾妲莉的對手。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제발. 당신이 그런 표정일 때는 일이 정상적으로 흘러가는 경우가 없었다고요.","JPN":"勘弁してください。あなたがその顔をする時は、決まって問題が起きるんですから。","ENG":"Please. Things never work out when you're making that face.","TWN":"拜託了。每當你露出那種表情時，事情就從來沒有正常過……"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞아, 크레데레. 우린 술래잡기가 아닌 보물찾기 중이잖아?","JPN":"そうだよ、クレデレ。私たちはあくまでお宝探しをしているのであって、鬼ごっこをしているわけじゃないんだから。","ENG":"Yeah, Credere. We're on a treasure hunt, not playing tag.","TWN":"沒錯，克蕾妲莉。我們不是在玩捉迷藏，而是在找寶藏，對吧？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"게임 도중 이탈은 반칙이라구.","JPN":"ゲームからの途中離脱行為は反則よ。","ENG":"Leaving during the game is cheating.","TWN":"遊戲中途退出可是犯規的喔。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"걱정 마시죠. 이런 송사리들은 순식간에 처리하고 합류할 테니.","JPN":"心配無用です。こんな雑魚たち、一瞬で片付けて合流しますから。","ENG":"Don't worry. Credere will take care of these chumps in no time and link up with you two.","TWN":"別擔心。克蕾妲莉會很快解決這些小嘍囉，然後和你們會合。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};